1	// Package convert provides shared type conversions between planner and gitproto
2	// types. It exists to avoid duplicating these helpers across strategy packages,
3	// while keeping planner and gitproto free of circular imports.
4	package convert
5	
6	import (
7		"github.com/go-git/go-git/v6/plumbing"
8	
9		"entire.io/entire/git-sync/internal/gitproto"
10		"entire.io/entire/git-sync/internal/planner"
11	)
12	
13	// DesiredRefs converts planner desired refs to gitproto desired refs.
14	func DesiredRefs(desired map[plumbing.ReferenceName]planner.DesiredRef) map[plumbing.ReferenceName]gitproto.DesiredRef {
15		out := make(map[plumbing.ReferenceName]gitproto.DesiredRef, len(desired))
16		for k, v := range desired {
17			out[k] = gitproto.DesiredRef{
18				SourceRef:  v.SourceRef,
19				TargetRef:  v.TargetRef,
20				SourceHash: v.SourceHash,
21				IsTag:      v.Kind == planner.RefKindTag,
22			}
23		}
24		return out
25	}
26	
27	// DesiredRefsForPlans converts only the desired refs referenced by the plans.
28	func DesiredRefsForPlans(
29		desired map[plumbing.ReferenceName]planner.DesiredRef,
30		plans []planner.BranchPlan,
31	) map[plumbing.ReferenceName]gitproto.DesiredRef {
32		out := make(map[plumbing.ReferenceName]gitproto.DesiredRef, len(plans))
33		for _, plan := range plans {
34			v, ok := desired[plan.TargetRef]
35			if !ok {
36				continue
37			}
38			out[plan.TargetRef] = gitproto.DesiredRef{
39				SourceRef:  v.SourceRef,
40				TargetRef:  v.TargetRef,
41				SourceHash: v.SourceHash,
42				IsTag:      v.Kind == planner.RefKindTag,
43			}
44		}
45		return out
46	}
47	
48	// PlansToPushPlans converts planner BranchPlans to gitproto PushPlans.
49	func PlansToPushPlans(plans []planner.BranchPlan) []gitproto.PushPlan {
50		out := make([]gitproto.PushPlan, len(plans))
51		for i, p := range plans {
52			out[i] = gitproto.PushPlan{
53				TargetRef:  p.TargetRef,
54				TargetHash: p.TargetHash,
55				SourceHash: p.SourceHash,
56				Delete:     p.Action == planner.ActionDelete,
57			}
58		}
59		return out
60	}
61	
62	// PlansToPushCommands converts planner BranchPlans directly to gitproto PushCommands.
63	func PlansToPushCommands(plans []planner.BranchPlan) []gitproto.PushCommand {
64		out := make([]gitproto.PushCommand, len(plans))
65		for i, p := range plans {
66			out[i] = gitproto.PushCommand{
67				Name:   p.TargetRef,
68				Old:    p.TargetHash,
69				New:    p.SourceHash,
70				Delete: p.Action == planner.ActionDelete,
71			}
72			if out[i].Delete {
73				out[i].New = plumbing.ZeroHash
74			}
75		}
76		return out
77	}
