20	// PushCommand represents a single ref update command.
21	type PushCommand struct {
22		Name   plumbing.ReferenceName
23		Old    plumbing.Hash
24		New    plumbing.Hash
25		Delete bool
26	}
27	
28	// Pusher wraps target-side receive-pack state behind a smaller execution API.
29	// When OnRejection is non-nil, per-ref ng statuses invoke it instead of erroring;
30	// pack-level unpack failure remains fatal.
31	//
32	// Returned by NewPusher as a pointer so callers can attach OnRejection after
33	// construction without worrying about whether downstream strategies have
34	// already captured a value copy.
35	type Pusher struct {
36		Conn        *Conn
37		Adv         *packp.AdvRefs
38		Verbose     bool
39		OnRejection func(refName plumbing.ReferenceName, status string)
40	}
41	
42	// NewPusher builds a target-side push executor.
43	func NewPusher(conn *Conn, adv *packp.AdvRefs, verbose bool) *Pusher {
44		return &Pusher{Conn: conn, Adv: adv, Verbose: verbose}
45	}
46	
47	// PushPack streams a pack to the target.
48	func (p *Pusher) PushPack(ctx context.Context, commands []PushCommand, pack io.ReadCloser) error {
49		return PushPack(ctx, p.Conn, p.Adv, commands, pack, p.Verbose, p.OnRejection)
50	}
51	
52	// PushCommands sends ref-only updates without a pack.
53	func (p *Pusher) PushCommands(ctx context.Context, commands []PushCommand) error {
54		return PushCommands(ctx, p.Conn, p.Adv, commands, p.Verbose, p.OnRejection)
55	}
56	
57	// PushObjects encodes and pushes locally materialized objects.
58	func (p *Pusher) PushObjects(ctx context.Context, commands []PushCommand, store storer.Storer, hashes []plumbing.Hash) error {
59		return PushObjects(ctx, p.Conn, p.Adv, commands, store, hashes, p.Verbose, p.OnRejection)
60	}
