62	// buildUpdateRequest builds the receive-pack update request.
63	func buildUpdateRequest(
64		adv *packp.AdvRefs,
65		commands []PushCommand,
66		verbose bool,
67	) (*packp.UpdateRequests, bool, bool, error) {
68		req := packp.NewUpdateRequests()
69		if sb := PreferredSideband(adv.Capabilities); sb != "" {
70			if err := req.Capabilities.Set(sb); err != nil {
71				return nil, false, false, fmt.Errorf("set capability: %w", err)
72			}
73		}
74		if adv.Capabilities.Supports(capability.ReportStatus) {
75			if err := req.Capabilities.Set(capability.ReportStatus); err != nil {
76				return nil, false, false, fmt.Errorf("set capability: %w", err)
77			}
78		}
79	
80		hasDelete := false
81		hasUpdates := false
82		for _, cmd := range commands {
83			c := &packp.Command{Name: cmd.Name, Old: cmd.Old}
84			if cmd.Delete {
85				c.New = plumbing.ZeroHash
86				hasDelete = true
87			} else {
88				c.New = cmd.New
89				hasUpdates = true
90			}
91			req.Commands = append(req.Commands, c)
92		}
93	
94		if hasDelete {
95			if !adv.Capabilities.Supports(capability.DeleteRefs) {
96				return nil, false, false, errors.New("target does not support delete-refs")
97			}
98			if err := req.Capabilities.Set(capability.DeleteRefs); err != nil {
99				return nil, false, false, fmt.Errorf("set capability: %w", err)
100			}
101		}
102	
103		_ = verbose // progress handling is server-side in HTTP mode
104		return req, hasDelete, hasUpdates, nil
105	}
