58	func ProbeConfig(source Endpoint, sourceAuth EndpointAuth, target *Endpoint, targetAuth EndpointAuth, protocol ProtocolMode, includeTags, allRefs, collectStats bool, excludeRefPrefixes []string, httpClient *http.Client) Config {
59		cfg := syncer.Config{
60			Source:             ToSyncerEndpoint(source, sourceAuth),
61			HTTPClient:         httpClient,
62			IncludeTags:        includeTags,
63			AllRefs:            allRefs,
64			ExcludeRefPrefixes: append([]string(nil), excludeRefPrefixes...),
65			ShowStats:          collectStats,
66			ProtocolMode:       protocolString(protocol),
67		}
68		if target != nil {
69			cfg.Target = ToSyncerEndpoint(*target, targetAuth)
70		}
71		return Config{raw: cfg}
72	}
