74	func SyncConfig(source Endpoint, sourceAuth EndpointAuth, target Endpoint, targetAuth EndpointAuth, scope RefScope, policy SyncPolicy, collectStats, dryRun bool, httpClient *http.Client) Config {
75		return Config{raw: syncer.Config{
76			Source:                 ToSyncerEndpoint(source, sourceAuth),
77			Target:                 ToSyncerEndpoint(target, targetAuth),
78			HTTPClient:             httpClient,
79			Branches:               append([]string(nil), scope.Branches...),
80			Mappings:               ToValidationMappings(scope.Mappings),
81			AllRefs:                scope.AllRefs,
82			ExcludeRefPrefixes:     append([]string(nil), scope.ExcludeRefPrefixes...),
83			IncludeTags:            policy.IncludeTags,
84			DryRun:                 dryRun,
85			ShowStats:              collectStats,
86			Mode:                   operationModeString(policy.Mode),
87			Force:                  policy.Force,
88			Prune:                  policy.Prune,
89			BestEffort:             policy.BestEffort,
90			ProtocolMode:           protocolString(policy.Protocol),
91			MaterializedMaxObjects: syncer.DefaultMaterializedMaxObjects,
92		}}
93	}
