95	func Probe(ctx context.Context, cfg Config) (syncer.ProbeResult, error) {
96		result, err := syncer.Probe(ctx, cfg.raw)
97		if err != nil {
98			return syncer.ProbeResult{}, err //nolint:wrapcheck // pass-through layer, caller wraps with context
99		}
100		return result, nil
101	}
