103	func Run(ctx context.Context, cfg Config) (syncer.Result, error) {
104		result, err := syncer.Run(ctx, cfg.raw)
105		if err != nil {
106			return syncer.Result{}, err //nolint:wrapcheck // pass-through layer, caller wraps with context
107		}
108		return result, nil
109	}
