111	func ToSyncerEndpoint(endpoint Endpoint, auth EndpointAuth) syncer.Endpoint {
112		return syncer.Endpoint{
113			URL:                    endpoint.URL,
114			Username:               auth.Username,
115			Token:                  auth.Token,
116			BearerToken:            auth.BearerToken,
117			SkipTLSVerify:          auth.SkipTLSVerify,
118			FollowInfoRefsRedirect: endpoint.FollowInfoRefsRedirect,
119		}
120	}
