122	func protocolString(mode ProtocolMode) string {
123		if mode == "" {
124			return string(ProtocolAuto)
125		}
126		return string(mode)
127	}
128	
129	func operationModeString(mode OperationMode) string {
130		if mode == "" {
131			return string(ModeSync)
132		}
133		return string(mode)
134	}
135	
136	func ToValidationMappings(mappings []RefMapping) []validation.RefMapping {
137		out := make([]validation.RefMapping, 0, len(mappings))
138		for _, mapping := range mappings {
139			out = append(out, validation.RefMapping{
140				Source: mapping.Source,
141				Target: mapping.Target,
142			})
143		}
144		return out
145	}
