146	func (r SyncRequest) Validate() error {
147		if r.Source.URL == "" {
148			return errors.New("source URL is required")
149		}
150		if r.Target.URL == "" {
151			return errors.New("target URL is required")
152		}
153		if err := validateOperationMode(r.Policy.Mode); err != nil {
154			return err
155		}
156		if _, err := validation.NormalizeProtocolMode(string(r.Policy.Protocol)); err != nil {
157			return fmt.Errorf("normalize protocol: %w", err)
158		}
159		if _, err := validation.ValidateMappings(validationMappings(r.Scope.Mappings), r.Scope.AllRefs); err != nil {
160			return fmt.Errorf("validate mappings: %w", err)
161		}
162		return nil
163	}
164	
165	func (r PlanRequest) Validate() error {
166		if r.Source.URL == "" {
167			return errors.New("source URL is required")
168		}
169		if r.Target.URL == "" {
170			return errors.New("target URL is required")
171		}
172		if err := validateOperationMode(r.Policy.Mode); err != nil {
173			return err
174		}
175		if _, err := validation.NormalizeProtocolMode(string(r.Policy.Protocol)); err != nil {
176			return fmt.Errorf("normalize protocol: %w", err)
177		}
178		if _, err := validation.ValidateMappings(validationMappings(r.Scope.Mappings), r.Scope.AllRefs); err != nil {
179			return fmt.Errorf("validate mappings: %w", err)
180		}
181		return nil
182	}
183	
184	func (r ProbeRequest) Validate() error {
185		if r.Source.URL == "" {
186			return errors.New("source URL is required")
187		}
188		if r.Target != nil && r.Target.URL == "" {
189			return errors.New("target URL is required when target endpoint is provided")
190		}
191		if _, err := validation.NormalizeProtocolMode(string(r.Protocol)); err != nil {
192			return fmt.Errorf("normalize protocol: %w", err)
193		}
194		return nil
195	}
