197	func bridgeEndpoint(ep Endpoint) internalbridge.Endpoint {
198		return internalbridge.Endpoint{
199			URL:                    ep.URL,
200			FollowInfoRefsRedirect: ep.FollowInfoRefsRedirect,
201		}
202	}
203	
204	func bridgeEndpointAuth(auth EndpointAuth) internalbridge.EndpointAuth {
205		return internalbridge.EndpointAuth{
206			Username:      auth.Username,
207			Token:         auth.Token,
208			BearerToken:   auth.BearerToken,
209			SkipTLSVerify: auth.SkipTLSVerify,
210		}
211	}
212	
213	func bridgeScope(scope RefScope) internalbridge.RefScope {
214		mappings := make([]internalbridge.RefMapping, 0, len(scope.Mappings))
215		for _, mapping := range scope.Mappings {
216			mappings = append(mappings, internalbridge.RefMapping{
217				Source: mapping.Source,
218				Target: mapping.Target,
219			})
220		}
221		return internalbridge.RefScope{
222			Branches:           append([]string(nil), scope.Branches...),
223			Mappings:           mappings,
224			AllRefs:            scope.AllRefs,
225			ExcludeRefPrefixes: append([]string(nil), scope.ExcludeRefPrefixes...),
226		}
227	}
228	
229	func bridgePolicy(policy SyncPolicy) internalbridge.SyncPolicy {
230		return internalbridge.SyncPolicy{
231			Mode:        internalbridge.OperationMode(policy.Mode),
232			IncludeTags: policy.IncludeTags,
233			Force:       policy.Force,
234			Prune:       policy.Prune,
235			BestEffort:  policy.BestEffort,
236			Protocol:    internalbridge.ProtocolMode(policy.Protocol),
237		}
238	}
