258			Mappings:               validationMappings(req.Scope.Mappings),
259			AllRefs:                req.Scope.AllRefs,
260			ExcludeRefPrefixes:     append([]string(nil), req.Scope.ExcludeRefPrefixes...),
261			IncludeTags:            req.Policy.IncludeTags,
262			DryRun:                 req.DryRun,
263			ShowStats:              req.Options.CollectStats,
264			MeasureMemory:          req.Options.MeasureMemory,
265			Progress:               req.Options.Progress,
266			Mode:                   operationModeString(req.Policy.Mode),
267			Force:                  req.Policy.Force,
268			Prune:                  req.Policy.Prune,
269			BestEffort:             req.Policy.BestEffort,
